script.js:
var colorA = document.getElementById("colorA");
var colorB = document.getElementById("colorB");
var tracksEl = document.getElementById("tracks");
var presetsEl = document.getElementById("presets");

var spaces = [
	{ label: "srgb", css: "in srgb" },
	{ label: "hsl", css: "in hsl" },
	{ label: "hwb", css: "in hwb" },
	{ label: "oklab", css: "in oklab" },
	{ label: "oklch", css: "in oklch", highlight: true },
	{ label: "oklch longer", css: "in oklch longer hue", highlight: true },
	{ label: "lab", css: "in lab" },
	{ label: "lch", css: "in lch" }
];

var presets = [
	["#0066ff", "#ff6600"],
	["#e02050", "#20e0a0"],
	["#6020e0", "#e0e020"],
	["#ff0080", "#00ff80"],
	["#003366", "#ffcc00"]
];

var gradEls = [];

function buildTracks() {
	tracksEl.innerHTML = "";
	gradEls = [];
	for (var i = 0; i < spaces.length; i++) {
		var track = document.createElement("div");
		track.className = "track";

		var label = document.createElement("div");
		label.className = "track-label";
		if (spaces[i].highlight) {
			label.innerHTML = '<span class="highlight">' + spaces[i].label + "</span>";
		} else {
			label.textContent = spaces[i].label;
		}

		var grad = document.createElement("div");
		grad.className = "grad";

		track.appendChild(label);
		track.appendChild(grad);
		tracksEl.appendChild(track);
		gradEls.push(grad);
	}
}

function buildPresets() {
	presetsEl.innerHTML = "";
	for (var i = 0; i < presets.length; i++) {
		(function (p) {
			var btn = document.createElement("button");
			btn.className = "preset-btn";
			btn.setAttribute("aria-label", "Preset " + p[0] + " to " + p[1]);
			var h1 = document.createElement("div");
			h1.className = "preset-half";
			h1.style.backgroundColor = p[0];
			var h2 = document.createElement("div");
			h2.className = "preset-half";
			h2.style.backgroundColor = p[1];
			btn.appendChild(h1);
			btn.appendChild(h2);
			btn.addEventListener("click", function () {
				colorA.value = p[0];
				colorB.value = p[1];
				render();
			});
			presetsEl.appendChild(btn);
		})(presets[i]);
	}
}

function render() {
	var a = colorA.value;
	var b = colorB.value;
	for (var i = 0; i < spaces.length; i++) {
		gradEls[i].style.background =
			"linear-gradient(to right " + spaces[i].css + ", " + a + ", " + b + ")";
	}
}

buildTracks();
buildPresets();
render();

colorA.addEventListener("input", render);
colorB.addEventListener("input", render);

style.css:
@import url("https://fonts.googleapis.com/css2?family=DM+Sans:opsz,wght@9..40,400;9..40,500;9..40,600&family=JetBrains+Mono:wght@400;500&display=swap");

*,
*::before,
*::after {
	margin: 0;
	padding: 0;
	box-sizing: border-box;
}

body {
	font-family: "DM Sans", sans-serif;
	background: #0d0d11;
	color: #d4d4de;
	line-height: 1.5;
	min-height: 100vh;
	-webkit-font-smoothing: antialiased;
}

.shell {
	max-width: 1100px;
	margin: 0 auto;
	padding: 1.5rem 1.5rem 3rem;
}

.topbar {
	display: flex;
	align-items: center;
	gap: 1rem;
	flex-wrap: wrap;
	margin-bottom: 1.5rem;
}

.topbar h1 {
	font-size: 1rem;
	font-weight: 600;
	letter-spacing: -0.02em;
	white-space: nowrap;
}

.pickers {
	display: flex;
	align-items: center;
	gap: 0.5rem;
	margin-left: auto;
}

.pickers span {
	font-family: "JetBrains Mono", monospace;
	font-size: 0.65rem;
	color: #5a5a68;
}

.pick-wrap {
	position: relative;
	width: 32px;
	height: 32px;
	border-radius: 8px;
	overflow: hidden;
	border: 2px solid #2a2a35;
	cursor: pointer;
	transition: border-color 0.2s;
}

.pick-wrap:hover {
	border-color: #5a5a68;
}

.pick-wrap input[type="color"] {
	position: absolute;
	inset: -6px;
	width: calc(100% + 12px);
	height: calc(100% + 12px);
	border: none;
	cursor: pointer;
	background: none;
}

.pick-wrap input::-webkit-color-swatch-wrapper {
	padding: 0;
}
.pick-wrap input::-webkit-color-swatch {
	border: none;
}
.pick-wrap input::-moz-color-swatch {
	border: none;
}

.presets {
	display: flex;
	gap: 0.35rem;
}

.preset-btn {
	display: flex;
	width: 20px;
	height: 20px;
	border-radius: 5px;
	border: 1.5px solid #2a2a35;
	cursor: pointer;
	overflow: hidden;
	transition: border-color 0.2s;
	background: none;
	padding: 0;
}

.preset-btn:hover {
	border-color: #5a5a68;
}

.preset-half {
	flex: 1;
	height: 100%;
}

.tracks {
	display: grid;
	gap: 0.625rem;
}

.track {
	display: grid;
	grid-template-columns: 90px 1fr;
	align-items: center;
	gap: 0.75rem;
	cursor: default;
	transition: opacity 0.25s;
	border-radius: 8px;
}

@media (max-width: 500px) {
	.track {
		grid-template-columns: 70px 1fr;
		gap: 0.5rem;
	}
}

.track-label {
	font-family: "JetBrains Mono", monospace;
	font-size: 0.68rem;
	font-weight: 500;
	color: #6a6a78;
	text-align: right;
	transition: color 0.25s;
}

.track-label .highlight {
	color: oklch(0.78 0.17 145);
}

.grad {
	height: 52px;
	border-radius: 8px;
	transition: background 0.15s, opacity 0.25s, transform 0.25s;
}

.tracks:hover .track {
	opacity: 0.3;
}
.tracks:hover .track:hover {
	opacity: 1;
}
.tracks:hover .track:hover .grad {
	transform: scaleY(1.15);
}
.tracks:hover .track:hover .track-label {
	color: #b0b0be;
}

.note {
	margin-top: 1.5rem;
	font-size: 0.72rem;
	color: #4a4a58;
	line-height: 1.6;
	max-width: 660px;
}

.note code {
	font-family: "JetBrains Mono", monospace;
	font-size: 0.68rem;
	background: #1a1a24;
	padding: 0.08rem 0.3rem;
	border-radius: 3px;
	color: #8a8a9a;
}

.cq {
	position: fixed;
	bottom: 0.6rem;
	right: 0.75rem;
	font-size: 0.58rem;
	font-family: "JetBrains Mono", monospace;
	color: #3a3a48;
	text-decoration: none;
	opacity: 0.5;
	transition: opacity 0.2s;
}

.cq:hover {
	opacity: 1;
	color: oklch(0.78 0.17 145);
}
